from pypdf import PdfReader
import glob
for f in sorted(glob.glob('documents/*.pdf')):
    print('=====', f, '=====')
    try:
        r=PdfReader(f)
        for p in r.pages:
            print(p.extract_text())
    except Exception as e:
        print('ERR', e)
"

